#include <stdio.h>

// Define gates using bitwise operators
int NOT(int a) { return ~a & 1; }
int AND(int a, int b) { return a & b; }
int OR(int a, int b) { return a | b; }
int NAND(int a, int b) { return NOT(AND(a, b)); }
int NOR(int a, int b) { return NOT(OR(a, b)); }
int XOR(int a, int b) { return a ^ b; }
int XNOR(int a, int b) { return NOT(XOR(a, b)); }

int main() {
    printf("A B | AND OR NOT NAND NOR XOR XNOR\n");
    printf("-" * 40);

    for (int a = 0; a <= 1; a++) {
        for (int b = 0; b <= 1; b++) {
            printf("\n%d %d |  %d   %d    %d    %d    %d   %d    %d",
                a, b, AND(a,b), OR(a,b), NOT(a), 
                NAND(a,b), NOR(a,b), XOR(a,b), XNOR(a,b));
        }
    }
    return 0;
}

