public class MajorityFunction {
    // Majority: output 1 when 2 or more inputs are 1
    public static int majority(int a, int b, int c) {
        // Using sum and comparison
        int sum = a + b + c;
        return (sum >= 2) ? 1 : 0;
    }

    // Using only AND and OR gates logic
    public static int majorityGates(int a, int b, int c) {
        // Y = AB + BC + AC (sum of products form)
        int ab = a & b;      // AND gate
        int bc = b & c;      // AND gate
        int ac = a & c;      // AND gate
        int result = ab | bc | ac;  // OR gates
        return result;
    }

    public static void main(String[] args) {
        System.out.println("A B C | Majority");
        System.out.println("-------------");
        for (int a = 0; a <= 1; a++) {
            for (int b = 0; b <= 1; b++) {
                for (int c = 0; c <= 1; c++) {
                    System.out.println(a + " " + b + " " + c + " |   " + majorityGates(a,b,c));
                }
            }
        }
    }
}

module logic_gates(input a, b, output y_and, y_or, y_not, y_nand, y_nor, y_xor, y_xnor);
    // AND gate
    assign y_and = a & b;

    // OR gate
    assign y_or = a | b;

    // NOT gate (inverter)
    assign y_not = ~a;

    // NAND gate
    assign y_nand = ~(a & b);

    // NOR gate
    assign y_nor = ~(a | b);

    // XOR gate
    assign y_xor = a ^ b;

    // XNOR gate
    assign y_xnor = ~(a ^ b);

endmodule
